import { SetTss } from './tss-setup.js';

const SearchParams = new URLSearchParams(document.currentScript.src.split('?')[1]);
const MbTssNonce = SearchParams.get('nonce');
const CTX = 'injection-tss';
const IsRepeatedFunc = (data, interval, threshold) => {
    console.debug(
        `TSS: Checking if repeated ${threshold} times for interval ${interval} against data: `,
        data
    );
    // return true if >= N occurrences in interval (milliseconds)
    const thisTime = Date.now();
    if (data.lastTime) {
        let thisInterval = thisTime - data.lastTime;
        if (thisInterval < interval) {
            data.lastCount++;
            if (data.lastCount >= threshold) {
                return true;
            }
        } else {
            data.lastTime = thisTime;
            data.lastCount = 1;
        }
    } else if (threshold === 1) {
        data.lastTime = thisTime;
        data.lastCount = 1;
        return true;
    } else {
        data.lastTime = thisTime;
        data.lastCount = 1;
    }
    return false;
};

SetTss(MbTssNonce, IsRepeatedFunc, CTX);
